from __future__ import annotations

import argparse
import csv
import io
from collections.abc import Mapping, Sequence
from pathlib import Path

import yaml

from tools.e2e_models import (
    CASES,
    COMPONENT_IDS,
    FACTORS,
    FLOW_ID,
    FLOW_STEPS,
    TARGET_CASES,
    E2eComponentVariant,
    E2eTargetCase,
    build_component_variants,
    element_label,
    markdown_escape,
)
from tools.generation_io import check_outputs, write_outputs

GENERATED_COMMENT = (
    "<!-- This file is generated by uv run python -m tools.generate_e2e_case_list. "
    "Do not edit manually. -->"
)

ELEMENT_KIND_LABELS = {
    "invariant": "不変条件",
    "action": "操作",
    "state": "状態",
    "data": "データ",
}

OPERATION_TYPE_LABELS = {
    "command": "コマンド",
    "query": "参照",
    "side_effect": "副作用",
    "evidence": "証跡確認",
}


def component_id(variant_id: str) -> str:
    return variant_id.split(".", maxsplit=1)[0]


def component_variants_by_id() -> dict[str, E2eComponentVariant]:
    return {variant.variant_id: variant for variant in build_component_variants()}


def selected_elements_by_factor(case_id: str) -> dict[str, str]:
    for case in CASES:
        if case.case_id == case_id:
            return dict(case.selected)
    raise KeyError(case_id)


def target_case_projects(target_case: E2eTargetCase) -> str:
    projects = sorted({assertion.project_id for assertion in target_case.runtime_assertions})
    if projects:
        return "<br>".join(f"`{project}`" for project in projects)
    variants = " ".join(target_case.selected_variants)
    for project in ("project_A", "project_B", "project_C"):
        if project in variants:
            return f"`{project}`"
    return "-"


def target_case_apis(target_case: E2eTargetCase) -> str:
    apis = sorted(
        {
            assertion.api_id
            for assertion in target_case.runtime_assertions
            if assertion.expected == "allowed"
        }
    )
    if apis:
        return "<br>".join(f"`{api}`" for api in apis)
    for api in ("API_A", "API_B", "API_C"):
        if f".{api}." in target_case.goal_variant:
            return f"`{api}`"
    variants = " ".join(target_case.selected_variants)
    matched_apis = [api for api in ("API_A", "API_B", "API_C") if api in variants]
    return "<br>".join(f"`{api}`" for api in matched_apis) if matched_apis else "-"


def render_generated_case_rows() -> list[str]:
    lines = [
        "## 5. 生成ケース一覧",
        "",
        "| ケースID | Coverage Group | Goal Component | 目的 | Project | API | "
        "Goal Variant | Component Variant | Runtime期待 | シナリオ |",
        "|---|---|---|---|---|---|---|---|---|---|",
    ]
    for target_case in TARGET_CASES:
        variants = "<br>".join(f"`{variant}`" for variant in target_case.selected_variants)
        runtime_assertions = (
            "<br>".join(
                f"`{assertion.project_id}` / `{assertion.api_id}`: `{assertion.expected}`"
                for assertion in target_case.runtime_assertions
            )
            if target_case.runtime_assertions
            else "-"
        )
        lines.append(
            f"| `{target_case.case_id}` | `{target_case.coverage_group}` | "
            f"`{target_case.goal_component}` | {markdown_escape(target_case.title)} | "
            f"{target_case_projects(target_case)} | {target_case_apis(target_case)} | "
            f"`{target_case.goal_variant}` | {variants} | {runtime_assertions} | "
            f"[`cases/{target_case.filename}`](cases/{target_case.filename}) |"
        )
    lines.append("")
    return lines


def as_mapping(value: object) -> Mapping[str, object]:
    return value if isinstance(value, dict) else {}


def as_sequence(value: object) -> Sequence[object]:
    return value if isinstance(value, list | tuple) else ()


def scalar_text(value: object, default: str = "-") -> str:
    return value if isinstance(value, str) else default


def bool_text(value: object) -> str:
    if isinstance(value, bool):
        return "はい" if value else "いいえ"
    return "-"


def load_yaml(path: Path) -> Mapping[str, object]:
    loaded = yaml.safe_load(path.read_text(encoding="utf-8"))
    return as_mapping(loaded)


def render_coverage_summary(variants: Sequence[E2eComponentVariant]) -> list[str]:
    lines = [
        "## 1. Coverage summary",
        "",
        "| Component | Variants | Covered variants | Cases | Coverage |",
        "|---|---:|---:|---:|---:|",
    ]
    covered_variants = {target_case.goal_variant for target_case in TARGET_CASES}
    for component in COMPONENT_IDS:
        component_variants = [
            variant.variant_id for variant in variants if variant.component_id == component
        ]
        covered = [variant for variant in component_variants if variant in covered_variants]
        component_cases = [
            target_case
            for target_case in TARGET_CASES
            if target_case.goal_component == component
        ]
        coverage = (
            f"{len(covered) / len(component_variants) * 100:.1f}%"
            if component_variants
            else "-"
        )
        lines.append(
            f"| `{component}` | {len(component_variants)} | {len(covered)} | "
            f"{len(component_cases)} | {coverage} |"
        )
    lines.append("")
    return lines


def render_component_sections(flow_root: Path) -> list[str]:
    lines = ["## 2. コンポーネントごとの要素", ""]
    for component_id in COMPONENT_IDS:
        component_root = flow_root / "components" / component_id
        component_doc = load_yaml(component_root / "component.manual.yaml")
        component = as_mapping(component_doc.get("component"))
        lines.extend(
            [
                f"### {component_id} {scalar_text(component.get('title'))}",
                "",
                "| 種別 | ID | タイトル | 補足 |",
                "|---|---|---|---|",
            ]
        )
        for invariant in as_sequence(component_doc.get("business_invariants")):
            invariant_map = as_mapping(invariant)
            lines.append(
                f"| {ELEMENT_KIND_LABELS['invariant']} | "
                f"`{scalar_text(invariant_map.get('id'))}` | - | "
                f"{markdown_escape(scalar_text(invariant_map.get('text')))} |"
            )
        actions_doc = load_yaml(component_root / "actions.manual.yaml")
        for action in as_sequence(actions_doc.get("actions")):
            action_map = as_mapping(action)
            operation_type = scalar_text(action_map.get("operation_type"))
            detail = (
                f"操作種別={OPERATION_TYPE_LABELS.get(operation_type, operation_type)}, "
                f"既定状態={scalar_text(action_map.get('default_result'))}"
            )
            lines.append(
                f"| {ELEMENT_KIND_LABELS['action']} | "
                f"`{scalar_text(action_map.get('id'))}` | "
                f"{markdown_escape(scalar_text(action_map.get('title')))} | "
                f"{markdown_escape(detail)} |"
            )
        states_doc = load_yaml(component_root / "states.manual.yaml")
        for state in as_sequence(states_doc.get("states")):
            state_map = as_mapping(state)
            continue_flow = state_map.get("continue_flow")
            detail = f"後続継続={bool_text(continue_flow)}"
            lines.append(
                f"| {ELEMENT_KIND_LABELS['state']} | "
                f"`{scalar_text(state_map.get('id'))}` | "
                f"{markdown_escape(scalar_text(state_map.get('title')))} | {detail} |"
            )
        data_doc = load_yaml(component_root / "data.manual.yaml")
        for data_profile in as_sequence(data_doc.get("data_profiles")):
            data_map = as_mapping(data_profile)
            tags = ", ".join(
                str(tag) for tag in as_sequence(data_map.get("tags")) if isinstance(tag, str)
            )
            lines.append(
                f"| {ELEMENT_KIND_LABELS['data']} | "
                f"`{scalar_text(data_map.get('id'))}` | "
                f"{markdown_escape(scalar_text(data_map.get('title')))} | "
                f"{markdown_escape(tags or '-')} |"
            )
        lines.append("")
    return lines


def render_case_list_markdown(root: Path = Path("docs/spec/50.e2e")) -> str:
    flow_root = root / FLOW_ID
    source_flow_root = (
        flow_root
        if (flow_root / "components").exists()
        else Path("docs/spec/50.e2e") / FLOW_ID
    )
    lines = [
        GENERATED_COMMENT,
        "",
        f"# {FLOW_ID} e2e component variants",
        "",
        "## 0. 対象フロー",
        "",
        "| Step | Operation | Endpoint | Template |",
        "|---|---|---|---|",
    ]
    for step in FLOW_STEPS:
        endpoint = f"{step.method} {step.path}" if step.method != "GET" else f"GET {step.path}"
        lines.append(
            f"| `{step.step_id}` | `{step.operation}` | `{markdown_escape(endpoint)}` | "
            f"`{step.template}` |"
        )
    lines.extend(
        [
            "",
            *render_coverage_summary(build_component_variants()),
            *render_component_sections(source_flow_root),
        ]
    )
    lines.extend(
        [
            "## 3. 枝刈り規則",
            "",
            "| Rule ID | 条件 | 結果 | 理由 |",
            "|---|---|---|---|",
            "| `P001` | `terminal=true` | 後続要因をN/A化 | unit-testと同じprefix terminal方式 |",
            "| `P002` | `reject_api_access_request_result=success` | "
            "approve provisioningとRuntime成功を除外 | "
            "rejectはAWS変更しない |",
            "| `P003` | approve失敗 | Runtime API呼び出しを除外 | subscription/scopeが存在しない |",
            "| `P004` | terminal step/status/reasonが同一 | 等価ケースを統合 | "
            "E2Eの重複実行を避ける |",
            "",
            "## 4. Smoke生成ケース一覧",
            "",
        ]
    )
    factor_columns = " | ".join(factor.factor_id for factor in FACTORS)
    factor_alignments = "|".join("---" for _ in FACTORS)
    lines.extend(
        [
            f"| ケースID | {factor_columns} | 種別 | Tier | 終了Step | シナリオ |",
            f"|---|{factor_alignments}|---|---|---|---|",
        ]
    )
    for case in CASES:
        selected = selected_elements_by_factor(case.case_id)
        selected_columns = " | ".join(
            markdown_escape(element_label(factor.factor_id, selected[factor.factor_id]))
            if factor.factor_id in selected
            else "-"
            for factor in FACTORS
        )
        lines.append(
            f"| `{case.case_id}` | {selected_columns} | `{case.kind}` | `{case.tier}` | "
            f"{markdown_escape(case.terminal_step)} | - |"
        )
    lines.extend(["", *render_generated_case_rows()])
    return "\n".join(lines)


def render_pruned_cases_csv() -> str:
    output = io.StringIO()
    writer = csv.writer(output, lineterminator="\n")
    factor_ids = [factor.factor_id for factor in FACTORS]
    writer.writerow(
        [
            "case_id",
            "case_group",
            "kind",
            "tier",
            "terminal_step",
            *factor_ids,
            "goal_component",
            "project",
            "api",
            "action",
            "state",
            "data",
            "goal_variant",
            "prerequisite_variants",
            "scenario_path",
        ]
    )
    for case in CASES:
        selected = selected_elements_by_factor(case.case_id)
        writer.writerow(
            [
                case.case_id,
                "smoke",
                case.kind,
                case.tier,
                case.terminal_step,
                *(selected.get(factor_id, "-") for factor_id in factor_ids),
                "-",
                "-",
                "-",
                "-",
                "-",
                "-",
                "-",
                "-",
                "-",
            ]
        )
    variants = component_variants_by_id()
    for target_case in TARGET_CASES:
        variant = variants[target_case.goal_variant]
        prerequisites = [
            selected_variant
            for selected_variant in target_case.selected_variants
            if selected_variant != target_case.goal_variant
        ]
        writer.writerow(
            [
                target_case.case_id,
                target_case.coverage_group,
                "-",
                "-",
                "-",
                *("-" for _ in factor_ids),
                variant.component_id,
                variant.project_id or "-",
                variant.api_id or "-",
                variant.action_id,
                variant.state_id,
                variant.data_id,
                target_case.goal_variant,
                ";".join(prerequisites) if prerequisites else "-",
                f"cases/{target_case.filename}",
            ]
        )
    return output.getvalue()


def rendered_outputs(output_root: Path = Path("docs/spec/50.e2e")) -> Mapping[Path, str]:
    flow_root = output_root / FLOW_ID
    return {
        flow_root / "case-list_gen.md": render_case_list_markdown(output_root),
        flow_root / "pruned-cases_gen.csv": render_pruned_cases_csv(),
    }


def generate(*, check: bool = False, output_root: Path = Path("docs/spec/50.e2e")) -> int:
    rendered = rendered_outputs(output_root)
    if check:
        return check_outputs(rendered)
    write_outputs(rendered)
    return 0


def main(argv: Sequence[str] | None = None) -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--check", action="store_true")
    args = parser.parse_args(argv)
    return generate(check=args.check)


if __name__ == "__main__":
    raise SystemExit(main())
